"use client";

import { useState, useRef, useCallback, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete, getRandomEncourage, triggerShake } from "@/lib/learningMessages";

// ===== 轮次配置 =====
interface RoundConfig {
  total: number;
  friends: number;
  perPerson: number;
  label: string;
}

const ROUNDS: RoundConfig[] = [
  { total: 8,  friends: 2, perPerson: 4, label: "第一轮：8 张纸分给 2 个同学" },
  { total: 12, friends: 3, perPerson: 4, label: "第二轮：12 张纸分给 3 个同学" },
  { total: 15, friends: 3, perPerson: 5, label: "第三轮：15 张纸分给 3 个同学" },
];

// 彩色纸的颜色（循环使用）
const PAPER_COLORS = [
  "#FB7185", "#38BDF8", "#34D399", "#FBBF24", "#A78BFA",
  "#F97316", "#EC4899", "#14B8A6", "#6366F1", "#EF4444",
  "#22C55E", "#3B82F6", "#EAB308", "#D946EF", "#06B6D4",
];

// 同学头像与名字
const FRIEND_EMOJIS = ["👦", "👧", "👦"];
const FRIEND_NAMES = ["小明", "小红", "小刚"];

type Phase = "playing" | "checking" | "roundResult" | "finished";

export default function TouchPage() {
  const [round, setRound] = useState(0);
  // assignedCount: 已经被点击分配的纸总数
  const [assignedCount, setAssignedCount] = useState(0);
  // 每个同学分到的纸数
  const [papersPerFriend, setPapersPerFriend] = useState<number[]>([0, 0]);
  // 当前高亮的同学索引
  const [activeFriend, setActiveFriend] = useState(0);
  const [phase, setPhase] = useState<Phase>("playing");
  // 每个同学得到的纸颜色索引
  const [friendPapers, setFriendPapers] = useState<number[][]>([[], []]);
  // 正在飞入的纸索引（-1 表示无）
  const [flyingIdx, setFlyingIdx] = useState(-1);
  const [encourageMsg, setEncourageMsg] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const papersAreaRef = useRef<HTMLDivElement | null>(null);
  // 用 ref 记录分配计数，避免闭包陷阱
  const assignedRef = useRef(0);
  const activeRef = useRef(0);

  const currentRound = ROUNDS[round];

  // 初始化一轮
  const initRound = useCallback((roundIdx: number) => {
    const r = ROUNDS[roundIdx];
    setPapersPerFriend(new Array(r.friends).fill(0));
    setAssignedCount(0);
    assignedRef.current = 0;
    setActiveFriend(0);
    activeRef.current = 0;
    setPhase("playing");
    setFriendPapers(new Array(r.friends).fill(null).map(() => []));
    setFlyingIdx(-1);
    setEncourageMsg("");
  }, []);

  // 首次加载初始化第一轮
  useEffect(() => {
    initRound(0);
  }, [initRound]);

  // 点击一张纸
  const handlePaperClick = (paperIdx: number) => {
    if (phase !== "playing") return;
    if (paperIdx !== assignedRef.current) return; // 必须按顺序点

    // 开始飞入动画
    setFlyingIdx(paperIdx);

    setTimeout(() => {
      const currentFriend = activeRef.current;

      setAssignedCount((prev) => {
        const next = prev + 1;
        assignedRef.current = next;
        return next;
      });

      setPapersPerFriend((prev) => {
        const next = [...prev];
        next[currentFriend] = next[currentFriend] + 1;
        return next;
      });

      setFriendPapers((prev) => {
        const next = [...prev];
        next[currentFriend] = [...next[currentFriend], paperIdx];
        return next;
      });

      // 切换到下一个同学
      const nextFriend = (currentFriend + 1) % currentRound.friends;
      activeRef.current = nextFriend;
      setActiveFriend(nextFriend);

      setFlyingIdx(-1);

      // 检查是否所有纸都分完了
      if (assignedRef.current + 1 >= currentRound.total) {
        setTimeout(() => {
          setPhase("checking");
        }, 300);
      }
    }, 350);
  };

  // 检查结果（由于按顺序分配，一定是平均的，这里做确认动画）
  const handleCheck = () => {
    setPhase("roundResult");
  };

  // 进入下一轮
  const handleNextRound = () => {
    if (round + 1 >= ROUNDS.length) {
      setPhase("finished");
    } else {
      setRound(round + 1);
      initRound(round + 1);
    }
  };

  return (
    <StepShell topicId="division" stepId="touch">
      <div className="space-y-5">
        {/* 轮次标题 */}
        <div className="text-center">
          <span className="inline-block rounded-full bg-[var(--primary)]/10 px-4 py-1.5 text-sm font-bold text-[var(--primary)]">
            第 {round + 1} / {ROUNDS.length} 轮
          </span>
          <p className="mt-2 text-[var(--text-secondary)]">{currentRound.label}</p>
        </div>

        {/* 游戏主区域 */}
        <div ref={papersAreaRef} className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
          {/* 彩色纸区域 */}
          <div className="mb-6">
            <p className="mb-3 text-center text-sm text-[var(--text-secondary)]">
              按顺序点击纸，把它分给下面的同学
            </p>
            <div className="flex flex-wrap justify-center gap-2">
              {Array.from({ length: currentRound.total }).map((_, i) => {
                const color = PAPER_COLORS[i % PAPER_COLORS.length];
                const isAssigned = i < assignedCount;
                const isFlying = flyingIdx === i;
                const isNext = i === assignedCount && phase === "playing";

                return (
                  <button
                    key={`paper-${round}-${i}`}
                    onClick={() => handlePaperClick(i)}
                    disabled={isAssigned || !isNext}
                    className={`
                      relative h-10 w-10 rounded-md transition-all duration-300
                      ${isAssigned
                        ? "scale-0 opacity-0 pointer-events-none"
                        : isFlying
                        ? "pointer-events-none"
                        : isNext
                        ? "cursor-pointer hover:scale-110 hover:shadow-md active:scale-95 animate-pulse-soft ring-2 ring-[var(--primary)] ring-offset-1"
                        : "cursor-default opacity-70"
                      }
                    `}
                    style={{
                      backgroundColor: color,
                      border: isNext ? `3px solid var(--primary)` : `2px solid ${color}`,
                    }}
                  >
                    {!isAssigned && !isFlying && (
                      <span className="absolute inset-0 flex items-center justify-center text-xs opacity-60">
                        ✦
                      </span>
                    )}
                    {isFlying && (
                      <span className="absolute inset-0 flex items-center justify-center text-xs animate-float-in">
                        ↓
                      </span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>

          {/* 同学区域 */}
          <div className="flex justify-center gap-4 sm:gap-6">
            {Array.from({ length: currentRound.friends }).map((_, fi) => {
              const isActive = activeFriend === fi && phase === "playing";
              return (
                <div
                  key={`friend-${round}-${fi}`}
                  className={`
                    flex flex-col items-center gap-2 rounded-2xl border-2 p-3 sm:p-4 transition-all duration-300 min-w-[72px] sm:min-w-[80px]
                    ${isActive
                      ? "border-[var(--primary)] scale-105 shadow-[var(--shadow-sm)]"
                      : "border-[var(--border)]"
                    }
                  `}
                  style={{ backgroundColor: isActive ? "var(--primary)/10" : "var(--bg-soft)" }}
                >
                  {/* 头像 */}
                  <div
                    className={`
                      flex h-12 w-12 items-center justify-center rounded-full text-2xl bg-[var(--bg-card)]
                      ${isActive ? "ring-2 ring-[var(--primary)] ring-offset-2" : ""}
                    `}
                  >
                    {FRIEND_EMOJIS[fi % FRIEND_EMOJIS.length]}
                  </div>
                  {/* 名字 */}
                  <span className="text-xs font-medium text-[var(--text)]">
                    {FRIEND_NAMES[fi % FRIEND_NAMES.length]}
                  </span>
                  {/* 收到的纸 */}
                  <div className="flex flex-wrap justify-center gap-1 min-h-[28px]">
                    {(friendPapers[fi] || []).map((pi) => (
                      <div
                        key={`fp-${round}-${fi}-${pi}`}
                        className="h-5 w-5 rounded-sm animate-float-in"
                        style={{ backgroundColor: PAPER_COLORS[pi % PAPER_COLORS.length] }}
                      />
                    ))}
                  </div>
                  {/* 数量 */}
                  <span className="text-lg font-bold text-[var(--text)]">
                    {papersPerFriend[fi] || 0}
                    <span className="text-xs font-normal text-[var(--text-muted)]"> 张</span>
                  </span>
                </div>
              );
            })}
          </div>

          {/* 鼓励消息 */}
          {encourageMsg && (
            <p className="mt-4 text-center text-sm text-[var(--accent)]">{encourageMsg}</p>
          )}
        </div>

        {/* 操作提示 */}
        {phase === "playing" && (
          <div className="text-center">
            <p className="text-sm text-[var(--text-muted)]">
              还剩 <span className="font-bold text-[var(--text)]">{currentRound.total - assignedCount}</span> 张纸没分
            </p>
            <p className="mt-1 text-xs text-[var(--text-muted)]">
              点击高亮的纸即可分配给当前同学
            </p>
          </div>
        )}

        {/* 检查按钮 */}
        {phase === "checking" && (
          <div className="flex justify-center">
            <button
              onClick={handleCheck}
              className="animate-float-in rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
            >
              检查结果
            </button>
          </div>
        )}

        {/* 轮次结果 */}
        {phase === "roundResult" && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-4xl animate-bounce-soft">🎉</div>
            <h3 className="mt-2 text-lg font-bold text-[var(--text)]">
              分得很平均！
            </h3>
            <p className="mt-2 text-[var(--text-secondary)]">
              {currentRound.total} 张纸分给 {currentRound.friends} 个同学，
              每人 <span className="font-bold text-[var(--primary)]">{currentRound.perPerson}</span> 张
            </p>
            <p className="mt-1 text-sm text-[var(--text-muted)]">
              {currentRound.total} ÷ {currentRound.friends} = {currentRound.perPerson}
            </p>

            <div className="mt-5 flex justify-center">
              <button
                onClick={handleNextRound}
                className="rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                {round + 1 < ROUNDS.length ? "下一轮 →" : "查看总结"}
              </button>
            </div>
          </div>
        )}

        {/* 完成卡片 */}
        {phase === "finished" && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">✋</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-[var(--text-secondary)]">
              你完成了三轮分纸游戏！
            </p>

            {/* 三轮总结 */}
            <div className="mt-4 space-y-2">
              {ROUNDS.map((r, i) => (
                <div
                  key={i}
                  className="rounded-[var(--radius-sm)] bg-[var(--bg-soft)] px-4 py-2 text-sm text-[var(--text)]"
                >
                  <span className="font-bold">{r.total} ÷ {r.friends} = {r.perPerson}</span>
                  <span className="text-[var(--text-muted)]"> — 每人 {r.perPerson} 张</span>
                </div>
              ))}
            </div>

            <p className="mt-4 text-[var(--text-secondary)]">
              把东西<strong className="text-[var(--primary)]">平均分</strong>给若干份，求每份多少，就是<strong className="text-[var(--accent)]">除法</strong>！
            </p>

            <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={() => { setRound(0); initRound(0); }}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                再玩一次
              </button>
              <Link
                href="/learn/division/compare"
                className="rounded-full bg-[var(--accent)] px-6 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                下一步：比一比 →
              </Link>
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
